import numpy as np
import random

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation = activation
        self.activation_prime = self.get_activation_prime(activation)
        self.input = None
        self.output = None
        self.delta = None

    def forward(self, X):
        self.input = X
        self.output = self.activation(np.dot(self.input, self.weights) + self.biases)
        return self.output

    def backward(self, delta_next, learning_rate):
        self.delta = delta_next.dot(self.weights.T) * self.activation_prime(self.input)
        weight_update = self.input.T.dot(delta_next)
        bias_update = np.sum(delta_next, axis=0, keepdims=True)
        self.weights -= learning_rate * weight_update
        self.biases -= learning_rate * bias_update
        return self.delta

    @staticmethod
    def get_activation_prime(activation):
        if activation == Layer.sigmoid:
            return Layer.sigmoid_prime
        elif activation == Layer.relu:
            return Layer.relu_prime
        elif activation == Layer.tanh:
            return Layer.tanh_prime

    @staticmethod
    def sigmoid(x):
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def sigmoid_prime(x):
        return x * (1 - x)

    @staticmethod
    def relu(x):
        return np.maximum(0, x)

    @staticmethod
    def relu_prime(x):
        return (x > 0).astype(float)

    @staticmethod
    def tanh(x):
        return np.tanh(x)

    @staticmethod
    def tanh_prime(x):
        return 1 - x ** 2

class NeuralNetwork:
    def __init__(self, input_size, hidden_sizes, output_size, activations):
        self.layers = []
        prev_size = input_size
        for size, activation in zip(hidden_sizes, activations):
            self.layers.append(Layer(prev_size, size, activation))
            prev_size = size
        self.layers.append(Layer(prev_size, output_size, activations[-1]))

    def forward(self, X):
        for layer in self.layers:
            X = layer.forward(X)
        return X

    def backward(self, y, learning_rate):
        delta = self.layers[-1].output - y
        for layer in reversed(self.layers):
            delta = layer.backward(delta, learning_rate)

