class Layer:
    def __init__(self, input_size, output_size, activation_function):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation_function = activation_function
        self.activation_derivative = self.get_activation_derivative(activation_function)

    def forward(self, inputs):
        self.inputs = inputs
        self.outputs = self.activation_function(np.dot(inputs, self.weights) + self.biases)
        return self.outputs

    def backward(self, downstream_gradient):
        activation_gradient = self.activation_derivative(self.outputs) * downstream_gradient
        input_gradient = np.dot(activation_gradient, self.weights.T)
        weight_gradient = np.dot(self.inputs.T, activation_gradient)
        bias_gradient = np.sum(activation_gradient, axis=0, keepdims=True)
        return input_gradient, weight_gradient, bias_gradient

    @staticmethod
    def get_activation_derivative(activation_function):
        if activation_function == Layer.sigmoid:
            return lambda x: x * (1 - x)
        elif activation_function == Layer.relu:
            return lambda x: 1 * (x > 0)
        elif activation_function == Layer.tanh:
            return lambda x: 1 - x ** 2

    @staticmethod
    def sigmoid(x):
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def relu(x):
        return np.maximum(0, x)

    @staticmethod
    def tanh(x):
        return np.tanh(x)

class NeuralNetwork:
    def __init__(self, input_size, hidden_sizes, output_size, activation_function):
        self.layers = []
        self.layers.append(Layer(input_size, hidden_sizes[0], activation_function))
        for i in range(1, len(hidden_sizes)):
            self.layers.append(Layer(hidden_sizes[i-1], hidden_sizes[i], activation_function))
        self.layers.append(Layer(hidden_sizes[-1], output_size, activation_function))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, labels, learning_rate):
        downstream_gradient = labels - self.layers[-1].outputs
        for layer in reversed(self.layers):
            downstream_gradient, weight_gradient, bias_gradient = layer.backward(downstream_gradient)
            layer.weights -= learning_rate * weight_gradient
            layer.biases -= learning_rate * bias_gradient

