import math

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(output_size, input_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros((output_size, 1))
        self.activation = activation
        self.z = None
        self.a = None
        self.delta = None

    def forward(self, a):
        self.z = np.dot(self.weights, a) + self.biases
        self.a = self.activation.forward(self.z)
        return self.a

    def backward(self, delta_next, learning_rate):
        self.delta = self.activation.backward(self.z) * delta_next
        weight_gradient = np.dot(self.delta, self.a.T)
        bias_gradient = np.sum(self.delta, axis=1, keepdims=True)
        self.weights -= learning_rate * weight_gradient
        self.biases -= learning_rate * bias_gradient
        return np.dot(self.weights.T, self.delta)

class Activation:
    def __init__(self, name):
        self.name = name

    def forward(self, z):
        if self.name == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif self.name == 'relu':
            return np.maximum(0, z)
        elif self.name == 'tanh':
            return np.tanh(z)

    def backward(self, z):
        if self.name == 'sigmoid':
            return self.forward(z) * (1 - self.forward(z))
        elif self.name == 'relu':
            return np.where(z > 0, 1, 0)
        elif self.name == 'tanh':
            return 1 - np.square(np.tanh(z))

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_sizes, activations):
        self.layers = []
        prev_size = input_size
        for size, activation_name in zip(hidden_sizes, activations):
            self.layers.append(Layer(prev_size, size, Activation(activation_name)))
            prev_size = size
        self.layers.append(Layer(prev_size, output_size, Activation('linear')))

    def forward(self, X):
        a = X.T
        for layer in self.layers:
            a = layer.forward(a)
        return a.T

    def backward(self, X, y, learning_rate):
        m = X.shape[0]
        y_pred = self.forward(X)
        delta = (y_pred - y.T) / m
        for layer in reversed(self.layers):
            delta = layer.backward(delta, learning_rate)

