import numpy as np

class Neuron:
    def __init__(self, num_inputs):
        self.weights = np.random.randn(num_inputs)
        self.bias = np.random.randn()
        self.activation = lambda x: 1 / (1 + np.exp(-x))
        self.derivative = lambda x: self.activation(x) * (1 - self.activation(x))

    def forward(self, inputs):
        weighted_sum = np.dot(inputs, self.weights) + self.bias
        return self.activation(weighted_sum)

    def backward(self, inputs, error, learning_rate):
        layer_gradient = error * self.derivative(np.dot(inputs, self.weights) + self.bias)
        weight_gradients = learning_rate * np.outer(inputs, layer_gradient)
        bias_gradient = learning_rate * layer_gradient
        self.weights -= weight_gradients
        self.bias -= bias_gradient

class Layer:
    def __init__(self, num_neurons, num_inputs):
        self.neurons = [Neuron(num_inputs) for _ in range(num_neurons)]

    def forward(self, inputs):
        return np.array([neuron.forward(inputs) for neuron in self.neurons])

    def backward(self, inputs, errors, learning_rate):
        for i, neuron in enumerate(self.neurons):
            neuron.backward(inputs, errors[i], learning_rate)

class NeuralNetwork:
    def __init__(self, input_size, hidden_sizes, output_size):
        self.layers = []
        self.layers.append(Layer(hidden_sizes[0], input_size))
        for i in range(1, len(hidden_sizes)):
            self.layers.append(Layer(hidden_sizes[i], hidden_sizes[i-1]))
        self.layers.append(Layer(output_size, hidden_sizes[-1]))

    def forward(self, inputs):
        for layer in self.layers:
            inputs = layer.forward(inputs)
        return inputs

    def backward(self, inputs, targets, learning_rate):
        outputs = self.forward(inputs)
        errors = targets - outputs
        for layer in reversed(self.layers):
            layer.backward(inputs, errors, learning_rate)
        return errors

