            self.weights.append(hidden_to_hidden)
            self.biases.append(np.zeros((1, self.hidden_layers[i+1])))

        hidden_to_output = np.random.randn(self.hidden_layers[-1], self.output_size) / np.sqrt(self.hidden_layers[-1])
        self.weights.append(hidden_to_output)
        self.biases.append(np.zeros((1, self.output_size)))

