class DenseLayer:
    def __init__(self, input_size, output_size, activation='relu'):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2 / input_size)
        self.biases = np.zeros(output_size)
        self.activation = self.get_activation(activation)
        self.activation_derivative = self.get_activation_derivative(activation)

    def forward(self, inputs):
        self.inputs = inputs
        self.outputs = self.activation(np.dot(inputs, self.weights) + self.biases)
        return self.outputs

    def backward(self, gradients):
        delta = gradients * self.activation_derivative(self.outputs)
        self.grad_weights = np.dot(self.inputs.T, delta)
        self.grad_biases = np.sum(delta, axis=0)
        return np.dot(delta, self.weights.T)

    def update(self, learning_rate):
        self.weights -= learning_rate * self.grad_weights
        self.biases -= learning_rate * self.grad_biases

    def get_activation(self, name):
        if name == 'relu':
            return lambda x: np.maximum(0, x)
        elif name == 'sigmoid':
            return lambda x: 1 / (1 + np.exp(-x))
        elif name == 'tanh':
            return lambda x: np.tanh(x)
        else:
            raise ValueError(f'Unknown activation function: {name}')

    def get_activation_derivative(self, name):
        if name == 'relu':
            return lambda x: (x > 0).astype(float)
        elif name == 'sigmoid':
            return lambda x: x * (1 - x)
        elif name == 'tanh':
            return lambda x: 1 - x ** 2
        else:
            raise ValueError(f'Unknown activation function: {name}')

