import numpy as np

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers=[]):
        self.input_size = input_size
        self.output_size = output_size
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        for i in range(len(self.hidden_layers) + 1):
            if i == 0:
                W = np.random.randn(self.hidden_layers[i], self.input_size) * np.sqrt(2 / self.input_size)
                b = np.zeros((self.hidden_layers[i], 1))
            elif i == len(self.hidden_layers):
                W = np.random.randn(self.output_size, self.hidden_layers[-1]) * np.sqrt(2 / self.hidden_layers[-1])
                b = np.zeros((self.output_size, 1))
            else:
                W = np.random.randn(self.hidden_layers[i], self.hidden_layers[i-1]) * np.sqrt(2 / self.hidden_layers[i-1])
                b = np.zeros((self.hidden_layers[i], 1))
            self.weights.append(W)
            self.biases.append(b)

    def activate(self, z, activation_function):
        if activation_function == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif activation_function == 'relu':
            return np.maximum(0, z)
        elif activation_function == 'linear':
            return z
        else:
            raise ValueError('Invalid activation function.')

    def forward_propagate(self, X):
        activations = [X.T]
        for i in range(len(self.weights)):
            z = np.dot(self.weights[i], activations[-1]) + self.biases[i]
            a = self.activate(z, 'sigmoid')
            activations.append(a)
        return activations

    def compute_cost(self, X, y, regularization_lambda=0):
        m = X.shape[1]
        activations = self.forward_propagate(X)
        hypothesis = activations[-1].T
        cost = -(1/m) * np.sum(y * np.log(hypothesis) + (1 - y) * np.log(1 - hypothesis))

        if regularization_lambda > 0:
            regularization_cost = 0
            for W in self.weights:
                regularization_cost += np.sum(W ** 2)
            cost += (regularization_lambda / (2 * m)) * regularization_cost

        return cost

    def compute_gradients(self, X, y, regularization_lambda=0):
        m = X.shape[1]
        activations = self.forward_propagate(X)
        delta = activations[-1].T - y
        dW = []
        db = []

        for i in range(len(self.weights), 0, -1):
            dW.insert(0, (1/m) * np.dot(delta, activations[i-1].T))
            db.insert(0, (1/m) * np.sum(delta, axis=1, keepdims=True))

            if i > 1:
                delta = np.dot(self.weights[i-1].T, delta) * self.activate(activations[i-1], 'sigmoid') * (1 - self.activate(activations[i-1], 'sigmoid'))

        if regularization_lambda > 0:
            for i in range(len(dW)):
                dW[i] += (regularization_lambda / m) * self.weights[i]

        return dW, db

    def update_parameters(self, dW, db, learning_rate):
        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * dW[i]
            self.biases[i] -= learning_rate * db[i]

    def train(self, X, y, num_iterations=10000, learning_rate=0.01, regularization_lambda=0):
        for i in range(num_iterations):
            dW, db = self.compute_gradients(X, y, regularization_lambda)
            self.update_parameters(dW, db, learning_rate)
            if i % 1000 == 0:
                print(f'Iteration {i}, Cost: {self.compute_cost(X, y, regularization_lambda)}')

    def predict(self, X):
        activations = self.forward_propagate(X)
        predictions = (activations[-1].T > 0.5).astype(int)
        return predictions

